content.text:
/* Fixed sizes that do not scale with user preferences */
.icon   { width: 24px; height: 24px; }
.border { border: 1px solid; }
.radius { border-radius: 8px; }

.card { font-size: 1.125rem; }  /* 18px */

/* 1em = 18px (the card's font-size) */
.card__title { font-size: 1.5em;  }  /* 27px */
.card__body  { padding:  1em;     }  /* 18px */

/* Compounding problem — avoid em for font-size in nested elements */
.nav        { font-size: 0.875em; }  /* 14px (from 16px parent) */
.nav .badge { font-size: 0.875em; }  /* 12.25px — compounds! */
/* Use rem instead to avoid this */

/* Optimal reading width: 45–75 characters */
article p {
  max-width: 65ch;  /* ~65 characters wide — scales with font size */
}

/* Form fields sized to fit expected content length */
input[type="date"]  { width: 12ch; }
input[type="time"]  { width: 8ch;  }

/* Full-height hero — avoid vh on mobile due to toolbar issue */
.hero {
  height: 100dvh;   /* dynamic viewport height — correct on mobile */
  min-height: 100svh; /* fallback for older browsers */
}

/* Fluid font size using viewport width */
h1 { font-size: clamp(1.75rem, 4vw, 3rem); }

/* Full-width band regardless of scrollbar */
.band { width: 100vw; margin-inline: calc(50% - 50vw); }

/* Responsive column */
.col { width: 50%; }     /* 50% of parent's width */

/* Vertical padding in % uses parent WIDTH — useful for aspect ratios */
.aspect-16-9 {
  width:           100%;
  padding-bottom:  56.25%;  /* 9/16 = 56.25% of width */
  position:        relative;
}
/* Modern alternative */
.video { aspect-ratio: 16 / 9; }

/* Center with translate (uses element's own size) */
.centered {
  position:  absolute;
  top:       50%;
  left:      50%;
  transform: translate(-50%, -50%);
}

/* Mix units: full width minus a fixed sidebar */
.main { width: calc(100% - 280px); }

/* Negative values */
.bleed { margin-inline: calc(-1 * var(--page-gutter)); }

/* Nested calc (or use + / - directly) */
.offset { top: calc(50% - 2rem); }

/* Arithmetic rules: space required around + and - */
.wrong  { width: calc(100%-48px); }   /* invalid — no spaces around - */
.right  { width: calc(100% - 48px); } /* valid */

/* Element is 50% wide but never more than 400px */
.card { width: min(50%, 400px); }

/* Font size is at least 1rem — grows with viewport beyond that */
.label { font-size: max(1rem, 1.5vw); }

/* Full-width image that never exceeds container */
img { width: min(100%, 800px); }

/* Font size: at least 1rem, scales at 2.5vw, max 1.5rem */
p { font-size: clamp(1rem, 2.5vw, 1.5rem); }

/* Fluid spacing: padding between 12px and 32px */
.section { padding-block: clamp(0.75rem, 3vw, 2rem); }

/* Container width: at least 320px, prefers 90%, max 1200px */
.container { width: clamp(320px, 90%, 1200px); }

/* Hex with alpha (last 2 hex digits = opacity) */
.overlay { background: #00000080; }  /* 50% black */

/* Modern rgb with alpha */
.backdrop { background: rgb(0 0 0 / 0.5); }

/* HSL — easy to create color families (same hue, vary lightness) */
:root {
  --blue-400: hsl(217 91% 65%);
  --blue-600: hsl(217 91% 50%);
  --blue-800: hsl(217 91% 35%);
}

/* oklch — perceptually uniform, wide gamut */
:root {
  --brand: oklch(65% 0.18 264);        /* P3 display color */
  --brand-light: oklch(80% 0.12 264);  /* proportionally lighter */
}

.text {
  /* line-height unitless: children inherit the ratio, not a fixed px */
  line-height: 1.5;  /* recommended */
  /* vs: */
  line-height: 24px;  /* bad: children with different font-size get wrong leading */
}

.icon {
  opacity: 0;
  transition: opacity 0.2s ease;
}
.icon:hover { opacity: 1; }

.card-image { aspect-ratio: 4/3; width: 100%; }

.sidebar {
  container-type: inline-size;  /* establishes a containment context */
  container-name: sidebar;
}

/* Inside .sidebar: cqi = 1% of the sidebar's inline (width) size */
.sidebar .widget {
  font-size: clamp(0.875rem, 2.5cqi, 1.125rem);
  padding:   2cqb;  /* relative to sidebar's block (height) size */
}

/* @container query — like @media but for the container */
@container sidebar (min-width: 300px) {
  .widget__title { font-size: 1.125rem; }
}

/* button.component.css */
:host {
  /* Expose sizing API as custom properties */
  --btn-padding-inline: 1rem;
  --btn-padding-block:  0.5rem;
  --btn-font-size:      1rem;
  --btn-radius:         6px;
  --btn-bg:             var(--color-brand, #3b82f6);
  --btn-color:          #ffffff;
}

.btn {
  padding:          var(--btn-padding-block) var(--btn-padding-inline);
  font-size:        var(--btn-font-size);
  border-radius:    var(--btn-radius);
  background:       var(--btn-bg);
  color:            var(--btn-color);
  line-height:      1;
}

/* Size variants via host attribute binding */
:host([size="sm"]) { --btn-font-size: 0.875rem; --btn-padding-block: 0.375rem; }
:host([size="lg"]) { --btn-font-size: 1.125rem; --btn-padding-block: 0.75rem;  }

.btn {
  transition: background-color 200ms ease, transform 150ms ease;
}

.modal {
  animation: slide-in 300ms ease forwards;
  animation-delay: 50ms;  /* slight delay before animation starts */
}

@keyframes slide-in {
  from { transform: translateY(-20px); opacity: 0; }
  to   { transform: translateY(0);     opacity: 1; }
}

/* Degrees — most common */
.icon-spin { transform: rotate(45deg); }

/* Turn — readable for full/partial rotations */
.half-turn  { transform: rotate(0.5turn);  }  /* 180° */
.quarter-turn { transform: rotate(0.25turn); }  /* 90° */

/* Gradients use angle to set the direction */
.gradient {
  background: linear-gradient(135deg, #3b82f6, #8b5cf6);
}

/* HSL hue is in degrees (0–360) — no unit needed but deg is valid */
.brand { color: hsl(217deg 91% 60%); }

/* Target high-DPI (Retina) screens */
@media (min-resolution: 2dppx) {
  .logo { background-image: url('logo@2x.png'); }
}

/* Equivalent using x shorthand */
@media (min-resolution: 2x) {
  .logo { background-image: url('logo@2x.png'); }
}

/* Prefer resolution-independent SVG or modern formats */
.icon { background-image: url('icon.svg'); }  /* no media query needed */

/* styles.css — design tokens */
:root {
  /* Spacing scale — multiples of 4px */
  --space-1:   0.25rem;   /*  4px */
  --space-2:   0.5rem;    /*  8px */
  --space-3:   0.75rem;   /* 12px */
  --space-4:   1rem;      /* 16px */
  --space-6:   1.5rem;    /* 24px */
  --space-8:   2rem;      /* 32px */
  --space-12:  3rem;      /* 48px */
  --space-16:  4rem;      /* 64px */

  /* Type scale */
  --text-xs:   0.75rem;   /* 12px */
  --text-sm:   0.875rem;  /* 14px */
  --text-base: 1rem;      /* 16px */
  --text-lg:   1.125rem;  /* 18px */
  --text-xl:   1.25rem;   /* 20px */
  --text-2xl:  1.5rem;    /* 24px */
  --text-3xl:  1.875rem;  /* 30px */

  /* Border radius */
  --radius-sm:   4px;
  --radius-md:   8px;
  --radius-lg:   12px;
  --radius-full: 9999px;

  /* Colors */
  --color-brand:      hsl(217 91% 60%);
  --color-brand-dark: hsl(217 91% 45%);
  --color-text:       hsl(215 28% 17%);
  --color-muted:      hsl(215 16% 47%);
  --color-border:     hsl(214 32% 91%);
  --color-bg:         hsl(0 0% 100%);
  --color-bg-subtle:  hsl(210 40% 98%);

  /* Duration */
  --duration-fast:   100ms;
  --duration-base:   200ms;
  --duration-slow:   400ms;
}

/* Dark theme override — swap color tokens */
@media (prefers-color-scheme: dark) {
  :root {
    --color-text:       hsl(210 40% 96%);
    --color-muted:      hsl(215 20% 65%);
    --color-border:     hsl(217 33% 17%);
    --color-bg:         hsl(222 47% 11%);
    --color-bg-subtle:  hsl(217 33% 17%);
  }
}

/* card.component.css — consumes tokens */
:host { display: block; }

.card {
  padding:          var(--space-6);
  border:           1px solid var(--color-border);
  border-radius:    var(--radius-lg);
  background:       var(--color-bg);
  color:            var(--color-text);
}

.card__title {
  font-size:   var(--text-xl);
  font-weight: 700;
  margin:      0 0 var(--space-2) 0;
}

.card__meta {
  font-size: var(--text-sm);
  color:     var(--color-muted);
}

.card__body { margin-block: var(--space-4); }

// design-tokens.ts — source of truth for programmatic access
export const tokens = {
  colors: {
    brand:     'var(--color-brand)',
    brandDark: 'var(--color-brand-dark)',
  },
  spacing: {
    sm:  'var(--space-2)',
    md:  'var(--space-4)',
    lg:  'var(--space-8)',
  }
} as const;

